"""
A Flask-like REST API handler with a simple class-based router.
Simulates routing, JSON handling, error responses, decorators, and type hints.
"""
from __future__ import annotations

import json
import functools
import time
from dataclasses import dataclass, field, asdict
from typing import Any, Callable, Optional
from enum import IntEnum


class HttpStatus(IntEnum):
    OK = 200
    CREATED = 201
    BAD_REQUEST = 400
    NOT_FOUND = 404
    METHOD_NOT_ALLOWED = 405
    INTERNAL_ERROR = 500


@dataclass
class Request:
    method: str
    path: str
    headers: dict[str, str] = field(default_factory=dict)
    body: Optional[str] = None

    def json(self) -> dict[str, Any]:
        if self.body is None:
            raise ValueError("Request body is empty")
        return json.loads(self.body)


@dataclass
class Response:
    status: int = HttpStatus.OK
    body: str = ""
    headers: dict[str, str] = field(default_factory=lambda: {"Content-Type": "application/json"})

    @staticmethod
    def json_response(data: Any, status: int = HttpStatus.OK) -> Response:
        return Response(status=status, body=json.dumps(data, default=str))

    @staticmethod
    def error(message: str, status: int = HttpStatus.BAD_REQUEST) -> Response:
        return Response.json_response({"error": message}, status=status)


@dataclass
class User:
    id: int
    name: str
    email: str
    created_at: str = ""

    def to_dict(self) -> dict[str, Any]:
        return asdict(self)


RouteHandler = Callable[[Request], Response]


def require_json(func: RouteHandler) -> RouteHandler:
    """Decorator that validates the request has a JSON content type."""
    @functools.wraps(func)
    def wrapper(request: Request) -> Response:
        content_type = request.headers.get("Content-Type", "")
        if "application/json" not in content_type and request.method in ("POST", "PUT"):
            return Response.error("Content-Type must be application/json", HttpStatus.BAD_REQUEST)
        return func(request)
    return wrapper


def log_request(func: RouteHandler) -> RouteHandler:
    """Decorator that logs request method and path."""
    @functools.wraps(func)
    def wrapper(request: Request) -> Response:
        start = time.monotonic()
        response = func(request)
        elapsed = (time.monotonic() - start) * 1000
        print(f"{request.method} {request.path} -> {response.status} ({elapsed:.1f}ms)")
        return response
    return wrapper


class Router:
    """Simple router that maps (method, path) pairs to handler functions."""

    def __init__(self) -> None:
        self._routes: dict[tuple[str, str], RouteHandler] = {}

    def route(self, path: str, methods: list[str] | None = None) -> Callable:
        allowed = methods or ["GET"]

        def decorator(func: RouteHandler) -> RouteHandler:
            for method in allowed:
                self._routes[(method.upper(), path)] = func
            return func
        return decorator

    def dispatch(self, request: Request) -> Response:
        handler = self._routes.get((request.method, request.path))
        if handler is None:
            any_path = any(p == request.path for (_, p) in self._routes)
            if any_path:
                return Response.error("Method not allowed", HttpStatus.METHOD_NOT_ALLOWED)
            return Response.error("Not found", HttpStatus.NOT_FOUND)
        try:
            return handler(request)
        except json.JSONDecodeError:
            return Response.error("Invalid JSON in request body")
        except Exception as exc:
            return Response.error(f"Internal error: {exc}", HttpStatus.INTERNAL_ERROR)


# --- Application setup ---

app = Router()
_users_db: dict[int, User] = {}
_next_id: int = 1


@app.route("/users", methods=["GET"])
@log_request
def list_users(request: Request) -> Response:
    """Return all users as a JSON array."""
    users = [u.to_dict() for u in _users_db.values()]
    return Response.json_response(users)


@app.route("/users", methods=["POST"])
@log_request
@require_json
def create_user(request: Request) -> Response:
    """Create a new user from JSON body."""
    global _next_id
    data = request.json()
    name = data.get("name")
    email = data.get("email")
    if not name or not email:
        return Response.error("Fields 'name' and 'email' are required")
    user = User(id=_next_id, name=name, email=email, created_at=time.strftime("%Y-%m-%dT%H:%M:%S"))
    _users_db[user.id] = user
    _next_id += 1
    return Response.json_response(user.to_dict(), status=HttpStatus.CREATED)


@app.route("/health", methods=["GET"])
def health_check(request: Request) -> Response:
    """Simple health-check endpoint."""
    return Response.json_response({"status": "ok", "users_count": len(_users_db)})


if __name__ == "__main__":
    # Simulate some API calls
    print("--- Health check ---")
    resp = app.dispatch(Request(method="GET", path="/health"))
    print(resp.body)

    print("\n--- Create user ---")
    resp = app.dispatch(Request(
        method="POST",
        path="/users",
        headers={"Content-Type": "application/json"},
        body=json.dumps({"name": "Alice", "email": "alice@example.com"}),
    ))
    print(resp.body)

    print("\n--- List users ---")
    resp = app.dispatch(Request(method="GET", path="/users"))
    print(resp.body)

    print("\n--- Not found ---")
    resp = app.dispatch(Request(method="GET", path="/missing"))
    print(resp.body)

"""
OOP patterns demonstrating inheritance, abstract methods, properties,
__slots__, dataclasses, enums, static methods, and class methods.
"""
from __future__ import annotations

import math
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from enum import Enum, auto
from typing import ClassVar, Iterator, Optional


class Color(Enum):
    """Color palette for shapes."""
    RED = auto()
    GREEN = auto()
    BLUE = auto()
    YELLOW = auto()
    BLACK = auto()

    def hex_code(self) -> str:
        mapping = {
            Color.RED: "#FF0000",
            Color.GREEN: "#00FF00",
            Color.BLUE: "#0000FF",
            Color.YELLOW: "#FFFF00",
            Color.BLACK: "#000000",
        }
        return mapping.get(self, "#FFFFFF")


class Shape(ABC):
    """Abstract base class for all shapes."""

    __slots__ = ("_color", "_label")

    _instance_count: ClassVar[int] = 0

    def __init__(self, color: Color = Color.BLACK, label: str = "") -> None:
        self._color = color
        self._label = label
        Shape._instance_count += 1

    @property
    def color(self) -> Color:
        return self._color

    @color.setter
    def color(self, value: Color) -> None:
        if not isinstance(value, Color):
            raise TypeError(f"Expected Color, got {type(value).__name__}")
        self._color = value

    @property
    def label(self) -> str:
        return self._label or f"{type(self).__name__}_{id(self) % 10000}"

    @abstractmethod
    def area(self) -> float:
        """Calculate the area of the shape."""
        ...

    @abstractmethod
    def perimeter(self) -> float:
        """Calculate the perimeter of the shape."""
        ...

    @classmethod
    def total_instances(cls) -> int:
        return cls._instance_count

    @staticmethod
    def is_valid_dimension(value: float) -> bool:
        return isinstance(value, (int, float)) and value > 0

    def __repr__(self) -> str:
        return f"{type(self).__name__}(color={self._color.name}, label={self.label!r})"


class Circle(Shape):
    """A circle defined by its radius."""

    __slots__ = ("_radius",)

    def __init__(self, radius: float, color: Color = Color.RED, label: str = "") -> None:
        super().__init__(color, label)
        if not self.is_valid_dimension(radius):
            raise ValueError(f"Invalid radius: {radius}")
        self._radius = radius

    @property
    def radius(self) -> float:
        return self._radius

    def area(self) -> float:
        return math.pi * self._radius ** 2

    def perimeter(self) -> float:
        return 2 * math.pi * self._radius

    @classmethod
    def unit_circle(cls) -> Circle:
        """Factory method for a unit circle."""
        return cls(radius=1.0, label="unit_circle")


class Rectangle(Shape):
    """A rectangle defined by width and height."""

    __slots__ = ("_width", "_height")

    def __init__(self, width: float, height: float,
                 color: Color = Color.BLUE, label: str = "") -> None:
        super().__init__(color, label)
        if not (self.is_valid_dimension(width) and self.is_valid_dimension(height)):
            raise ValueError(f"Invalid dimensions: {width}x{height}")
        self._width = width
        self._height = height

    @property
    def width(self) -> float:
        return self._width

    @property
    def height(self) -> float:
        return self._height

    @property
    def is_square(self) -> bool:
        return math.isclose(self._width, self._height)

    def area(self) -> float:
        return self._width * self._height

    def perimeter(self) -> float:
        return 2 * (self._width + self._height)

    def diagonal(self) -> float:
        return math.hypot(self._width, self._height)

    @classmethod
    def square(cls, side: float, **kwargs: object) -> Rectangle:
        """Factory method for a square."""
        return cls(side, side, **kwargs)  # type: ignore[arg-type]


@dataclass
class ShapeCollection:
    """A named collection of shapes with aggregate operations."""
    name: str
    shapes: list[Shape] = field(default_factory=list)

    def add(self, shape: Shape) -> None:
        self.shapes.append(shape)

    def total_area(self) -> float:
        return sum(s.area() for s in self.shapes)

    def total_perimeter(self) -> float:
        return sum(s.perimeter() for s in self.shapes)

    def filter_by_color(self, color: Color) -> list[Shape]:
        return [s for s in self.shapes if s.color == color]

    def filter_by_type(self, shape_type: type) -> list[Shape]:
        return [s for s in self.shapes if isinstance(s, shape_type)]

    def largest(self) -> Optional[Shape]:
        if not self.shapes:
            return None
        return max(self.shapes, key=lambda s: s.area())

    def sorted_by_area(self, reverse: bool = False) -> list[Shape]:
        return sorted(self.shapes, key=lambda s: s.area(), reverse=reverse)

    def __iter__(self) -> Iterator[Shape]:
        return iter(self.shapes)

    def __len__(self) -> int:
        return len(self.shapes)

    def summary(self) -> str:
        lines = [
            f"Collection: {self.name} ({len(self)} shapes)",
            f"  Total area:      {self.total_area():.4f}",
            f"  Total perimeter:  {self.total_perimeter():.4f}",
        ]
        if (big := self.largest()) is not None:
            lines.append(f"  Largest:          {big!r} (area={big.area():.4f})")
        return "\n".join(lines)


if __name__ == "__main__":
    collection = ShapeCollection(name="demo")

    collection.add(Circle(5.0, color=Color.RED, label="big_circle"))
    collection.add(Circle.unit_circle())
    collection.add(Rectangle(3.0, 4.0, color=Color.GREEN))
    collection.add(Rectangle.square(2.5, color=Color.BLUE, label="my_square"))
    collection.add(Circle(2.0, color=Color.YELLOW))

    print(collection.summary())
    print()

    print("Shapes sorted by area (descending):")
    for shape in collection.sorted_by_area(reverse=True):
        print(f"  {shape!r}  area={shape.area():.4f}")

    print(f"\nRed shapes: {collection.filter_by_color(Color.RED)}")
    print(f"Circles:    {collection.filter_by_type(Circle)}")
    print(f"Total Shape instances created: {Shape.total_instances()}")

"""
Mini ORM-like system with model definitions, field validation,
relationship mapping, and a fluent query builder.

Supports model registration via metaclass, typed fields with validators,
one-to-many / many-to-many relationships, and an in-memory storage backend.
"""

from __future__ import annotations

import re
import uuid
from contextlib import contextmanager
from dataclasses import dataclass, field
from datetime import datetime, timezone
from enum import Enum, auto
from typing import (
    Any,
    Callable,
    ClassVar,
    Dict,
    Generator,
    Generic,
    Iterator,
    List,
    Optional,
    Sequence,
    Tuple,
    Type,
    TypeVar,
    Union,
)

# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------

class ORMError(Exception):
    """Base exception for every ORM-related error."""


class ValidationError(ORMError):
    """Raised when a field value fails validation."""

    def __init__(self, field_name: str, message: str) -> None:
        self.field_name = field_name
        super().__init__(f"Validation failed on '{field_name}': {message}")


class FieldRequiredError(ValidationError):
    """Raised when a required field is left empty."""

    def __init__(self, field_name: str) -> None:
        super().__init__(field_name, "This field is required")


class RecordNotFoundError(ORMError):
    """Raised when a query expects exactly one record but finds none."""


class DuplicateModelError(ORMError):
    """Raised when two models share the same table name."""


class TransactionError(ORMError):
    """Raised on transaction commit / rollback failures."""


# ---------------------------------------------------------------------------
# Field descriptors
# ---------------------------------------------------------------------------

T = TypeVar("T")
M = TypeVar("M", bound="Model")


class FieldType(Enum):
    STRING = auto()
    INTEGER = auto()
    FLOAT = auto()
    BOOLEAN = auto()
    DATETIME = auto()
    UUID = auto()


@dataclass
class FieldDescriptor(Generic[T]):
    """Metadata and validation logic for a single model field."""

    name: str = ""
    field_type: FieldType = FieldType.STRING
    required: bool = True
    default: Optional[T] = None
    default_factory: Optional[Callable[[], T]] = None
    max_length: Optional[int] = None
    min_value: Optional[Union[int, float]] = None
    max_value: Optional[Union[int, float]] = None
    regex: Optional[str] = None
    validators: List[Callable[[T], bool]] = field(default_factory=list)
    primary_key: bool = False

    # --- descriptor protocol ---
    def __set_name__(self, owner: type, name: str) -> None:
        self.name = name
        self._attr = f"_field_{name}"

    def __get__(self, obj: Any, objtype: Optional[type] = None) -> Any:
        if obj is None:
            return self
        return getattr(obj, self._attr, self.default)

    def __set__(self, obj: Any, value: Any) -> None:
        self.validate(value)
        setattr(obj, self._attr, value)

    # --- validation ---
    def validate(self, value: Any) -> None:
        if value is None:
            if self.required and self.default is None and self.default_factory is None:
                raise FieldRequiredError(self.name)
            return

        if self.field_type == FieldType.STRING:
            if not isinstance(value, str):
                raise ValidationError(self.name, f"Expected str, got {type(value).__name__}")
            if self.max_length is not None and len(value) > self.max_length:
                raise ValidationError(self.name, f"Exceeds max length {self.max_length}")
            if self.regex and not re.match(self.regex, value):
                raise ValidationError(self.name, f"Does not match pattern {self.regex}")

        if self.field_type in (FieldType.INTEGER, FieldType.FLOAT):
            if self.min_value is not None and value < self.min_value:
                raise ValidationError(self.name, f"Below minimum {self.min_value}")
            if self.max_value is not None and value > self.max_value:
                raise ValidationError(self.name, f"Above maximum {self.max_value}")

        for fn in self.validators:
            if not fn(value):
                raise ValidationError(self.name, f"Custom validator {fn.__name__} failed")


class Relationship:
    """Describes a lazy-loaded one-to-many or many-to-many link."""

    def __init__(
        self,
        target_model: str,
        *,
        back_populates: Optional[str] = None,
        many_to_many: bool = False,
    ) -> None:
        self.target_model = target_model
        self.back_populates = back_populates
        self.many_to_many = many_to_many

    def resolve(self) -> Type[Model]:
        return ModelRegistry.get_model(self.target_model)


# ---------------------------------------------------------------------------
# Registry + metaclass
# ---------------------------------------------------------------------------

class ModelRegistry:
    """Central catalogue of all registered model classes."""

    _models: ClassVar[Dict[str, Type[Model]]] = {}

    @classmethod
    def register(cls, model_cls: Type[Model]) -> None:
        table = model_cls.__table_name__
        if table in cls._models:
            raise DuplicateModelError(f"Table '{table}' already registered")
        cls._models[table] = model_cls

    @classmethod
    def get_model(cls, name: str) -> Type[Model]:
        for table, model_cls in cls._models.items():
            if model_cls.__name__ == name or table == name:
                return model_cls
        raise ORMError(f"Unknown model '{name}'")

    @classmethod
    def all_models(cls) -> Generator[Tuple[str, Type[Model]], None, None]:
        yield from cls._models.items()

    @classmethod
    def clear(cls) -> None:
        cls._models.clear()


class ModelMeta(type):
    """Metaclass that auto-registers every Model subclass."""

    def __new__(
        mcs,
        name: str,
        bases: Tuple[type, ...],
        namespace: Dict[str, Any],
        **kwargs: Any,
    ) -> ModelMeta:
        cls = super().__new__(mcs, name, bases, namespace)
        if name != "Model" and any(isinstance(b, ModelMeta) for b in bases):
            if "__table_name__" not in namespace:
                cls.__table_name__ = name.lower() + "s"  # type: ignore[attr-defined]
            ModelRegistry.register(cls)  # type: ignore[arg-type]
        return cls  # type: ignore[return-value]


# ---------------------------------------------------------------------------
# In-memory storage (acts as a tiny database backend)
# ---------------------------------------------------------------------------

class Storage:
    """Thread-unsafe in-memory store keyed by table name."""

    _tables: ClassVar[Dict[str, List[Dict[str, Any]]]] = {}
    _transaction_stack: ClassVar[List[Dict[str, List[Dict[str, Any]]]]] = []

    @classmethod
    def _ensure_table(cls, table: str) -> List[Dict[str, Any]]:
        if table not in cls._tables:
            cls._tables[table] = []
        return cls._tables[table]

    @classmethod
    def insert(cls, table: str, row: Dict[str, Any]) -> None:
        cls._ensure_table(table).append(row)

    @classmethod
    def select_all(cls, table: str) -> List[Dict[str, Any]]:
        return list(cls._ensure_table(table))

    @classmethod
    def delete_where(cls, table: str, predicate: Callable[[Dict[str, Any]], bool]) -> int:
        rows = cls._ensure_table(table)
        before = len(rows)
        cls._tables[table] = [r for r in rows if not predicate(r)]
        return before - len(cls._tables[table])

    @classmethod
    def snapshot(cls) -> Dict[str, List[Dict[str, Any]]]:
        return {t: list(rows) for t, rows in cls._tables.items()}

    @classmethod
    def restore(cls, snap: Dict[str, List[Dict[str, Any]]]) -> None:
        cls._tables = snap

    @classmethod
    @contextmanager
    def transaction(cls) -> Generator[None, None, None]:
        snap = cls.snapshot()
        cls._transaction_stack.append(snap)
        try:
            yield
        except Exception as exc:
            cls.restore(cls._transaction_stack.pop())
            raise TransactionError("Transaction rolled back") from exc
        else:
            cls._transaction_stack.pop()

    @classmethod
    def reset(cls) -> None:
        cls._tables.clear()
        cls._transaction_stack.clear()


# ---------------------------------------------------------------------------
# Query builder (fluent interface)
# ---------------------------------------------------------------------------

class QueryBuilder(Generic[M]):
    """Chainable query constructor that operates over the in-memory store."""

    def __init__(self, model_cls: Type[M]) -> None:
        self._model = model_cls
        self._filters: List[Callable[[Dict[str, Any]], bool]] = []
        self._order_key: Optional[str] = None
        self._order_desc: bool = False
        self._limit: Optional[int] = None
        self._offset: int = 0

    # --- chaining methods ---
    def filter(self, predicate: Callable[[Dict[str, Any]], bool]) -> QueryBuilder[M]:
        self._filters.append(predicate)
        return self

    def filter_by(self, **kwargs: Any) -> QueryBuilder[M]:
        for key, val in kwargs.items():
            self._filters.append(lambda row, k=key, v=val: row.get(k) == v)
        return self

    def order_by(self, key: str, *, desc: bool = False) -> QueryBuilder[M]:
        self._order_key = key
        self._order_desc = desc
        return self

    def limit(self, n: int) -> QueryBuilder[M]:
        self._limit = n
        return self

    def offset(self, n: int) -> QueryBuilder[M]:
        self._offset = n
        return self

    # --- terminal methods ---
    def _raw_rows(self) -> List[Dict[str, Any]]:
        rows = Storage.select_all(self._model.__table_name__)
        for pred in self._filters:
            rows = [r for r in rows if pred(r)]
        if self._order_key:
            rows.sort(key=lambda r: r.get(self._order_key, ""), reverse=self._order_desc)
        rows = rows[self._offset:]
        if self._limit is not None:
            rows = rows[: self._limit]
        return rows

    def all(self) -> List[M]:
        return [self._model.from_dict(r) for r in self._raw_rows()]

    def first(self) -> Optional[M]:
        rows = self.limit(1)._raw_rows()
        return self._model.from_dict(rows[0]) if rows else None

    def one(self) -> M:
        result = self.first()
        if result is None:
            raise RecordNotFoundError(f"No {self._model.__name__} matched the query")
        return result

    def count(self) -> int:
        return len(self._raw_rows())

    def exists(self) -> bool:
        return self.count() > 0

    def delete(self) -> int:
        matching_ids = {r.get("id") for r in self._raw_rows()}
        return Storage.delete_where(
            self._model.__table_name__, lambda r: r.get("id") in matching_ids
        )

    def iterate(self, batch_size: int = 50) -> Generator[M, None, None]:
        rows = self._raw_rows()
        for i in range(0, len(rows), batch_size):
            for row in rows[i : i + batch_size]:
                yield self._model.from_dict(row)

    def __repr__(self) -> str:
        parts = [f"QueryBuilder({self._model.__name__})"]
        if self._filters:
            parts.append(f".filter(x{len(self._filters)})")
        if self._order_key:
            direction = "desc" if self._order_desc else "asc"
            parts.append(f".order_by({self._order_key!r}, {direction})")
        if self._limit is not None:
            parts.append(f".limit({self._limit})")
        return "".join(parts)


# ---------------------------------------------------------------------------
# Base Model
# ---------------------------------------------------------------------------

class Model(metaclass=ModelMeta):
    """Abstract base for all ORM models."""

    __table_name__: ClassVar[str] = ""

    id: FieldDescriptor[str] = FieldDescriptor(
        field_type=FieldType.UUID, required=False, primary_key=True
    )

    def __init__(self, **kwargs: Any) -> None:
        if "id" not in kwargs:
            kwargs["id"] = str(uuid.uuid4())

        for key, val in kwargs.items():
            setattr(self, key, val)

        self._created_at = datetime.now(timezone.utc)
        self._dirty: bool = True

    # --- magic methods ---
    def __repr__(self) -> str:
        fields = ", ".join(f"{k}={v!r}" for k, v in self.to_dict().items())
        return f"{type(self).__name__}({fields})"

    def __str__(self) -> str:
        return f"<{type(self).__name__} id={self.id}>"

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Model):
            return NotImplemented
        return type(self) is type(other) and self.id == other.id

    def __hash__(self) -> int:
        return hash((type(self).__name__, self.id))

    # --- persistence helpers ---
    @property
    def created_at(self) -> datetime:
        return self._created_at

    @property
    def is_dirty(self) -> bool:
        return self._dirty

    def to_dict(self) -> Dict[str, Any]:
        result: Dict[str, Any] = {}
        for cls in type(self).__mro__:
            for attr_name, attr_val in vars(cls).items():
                if isinstance(attr_val, FieldDescriptor):
                    result[attr_name] = getattr(self, attr_name)
        result["_created_at"] = self._created_at.isoformat()
        return result

    @classmethod
    def from_dict(cls: Type[M], data: Dict[str, Any]) -> M:
        filtered = {
            k: v
            for k, v in data.items()
            if not k.startswith("_") and k != "_created_at"
        }
        instance = cls(**filtered)
        if "_created_at" in data:
            instance._created_at = datetime.fromisoformat(data["_created_at"])
        instance._dirty = False
        return instance

    def save(self) -> None:
        table = type(self).__table_name__
        Storage.delete_where(table, lambda r: r.get("id") == self.id)
        Storage.insert(table, self.to_dict())
        self._dirty = False

    @classmethod
    def query(cls: Type[M]) -> QueryBuilder[M]:
        return QueryBuilder(cls)

    @classmethod
    def get_by_id(cls: Type[M], record_id: str) -> M:
        return cls.query().filter_by(id=record_id).one()

